export type CircuitState = "closed" | "open" | "half-open";

export interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: number[];
}

export const DEFAULT_CIRCUIT_BREAKER_OPTIONS: ResolvedCircuitBreakerOptions = {
  threshold: 5,
  cooldown: 30_000,
  halfOpenMaxRequests: 1,
  failureStatusCodes: [408, 409, 425, 429, 500, 502, 503, 504],
};

export function resolveCircuitBreakerOptions(
  option: true | CircuitBreakerOptions
): ResolvedCircuitBreakerOptions {
  if (option === true) {
    return { ...DEFAULT_CIRCUIT_BREAKER_OPTIONS };
  }
  return {
    threshold: option.threshold ?? DEFAULT_CIRCUIT_BREAKER_OPTIONS.threshold,
    cooldown: option.cooldown ?? DEFAULT_CIRCUIT_BREAKER_OPTIONS.cooldown,
    halfOpenMaxRequests:
      option.halfOpenMaxRequests ??
      DEFAULT_CIRCUIT_BREAKER_OPTIONS.halfOpenMaxRequests,
    failureStatusCodes:
      option.failureStatusCodes ??
      DEFAULT_CIRCUIT_BREAKER_OPTIONS.failureStatusCodes,
  };
}

interface CircuitEntry {
  state: CircuitState;
  consecutiveFailures: number;
  openedAt: number;
  halfOpenActive: number;
}

export type CircuitBreakerStore = Map<string, CircuitEntry>;

export function createCircuitBreakerStore(): CircuitBreakerStore {
  return new Map();
}

function getEntry(store: CircuitBreakerStore, origin: string): CircuitEntry {
  let entry = store.get(origin);
  if (!entry) {
    entry = {
      state: "closed",
      consecutiveFailures: 0,
      openedAt: 0,
      halfOpenActive: 0,
    };
    store.set(origin, entry);
  }
  return entry;
}

// Lazily transitions open -> half-open once the cooldown has elapsed, so
// state is always evaluated against the current Date.now() (keeps fake timers deterministic).
function refreshState(entry: CircuitEntry, cooldown: number): void {
  if (entry.state === "open" && Date.now() - entry.openedAt >= cooldown) {
    entry.state = "half-open";
  }
}

export interface CircuitAdmission {
  allowed: boolean;
  isProbe: boolean;
}

export function admitRequest(
  store: CircuitBreakerStore,
  origin: string,
  options: ResolvedCircuitBreakerOptions
): CircuitAdmission {
  const entry = getEntry(store, origin);
  refreshState(entry, options.cooldown);

  if (entry.state === "open") {
    return { allowed: false, isProbe: false };
  }

  if (entry.state === "half-open") {
    if (entry.halfOpenActive >= options.halfOpenMaxRequests) {
      return { allowed: false, isProbe: false };
    }
    entry.halfOpenActive++;
    return { allowed: true, isProbe: true };
  }

  return { allowed: true, isProbe: false };
}

export function releaseProbeSlot(
  store: CircuitBreakerStore,
  origin: string,
  isProbe: boolean
): void {
  if (!isProbe) {
    return;
  }
  const entry = getEntry(store, origin);
  if (entry.halfOpenActive > 0) {
    entry.halfOpenActive--;
  }
}

export function recordCircuitSuccess(
  store: CircuitBreakerStore,
  origin: string,
  isProbe: boolean
): void {
  const entry = getEntry(store, origin);
  entry.consecutiveFailures = 0;
  entry.state = "closed";
  releaseProbeSlot(store, origin, isProbe);
}

export function recordCircuitFailure(
  store: CircuitBreakerStore,
  origin: string,
  options: ResolvedCircuitBreakerOptions,
  isProbe: boolean
): void {
  const entry = getEntry(store, origin);
  entry.consecutiveFailures++;

  const wasHalfOpen = entry.state === "half-open";
  releaseProbeSlot(store, origin, isProbe);

  if (wasHalfOpen) {
    // half-open -> open: restart the cooldown from this failure time.
    entry.state = "open";
    entry.openedAt = Date.now();
  } else if (entry.consecutiveFailures >= options.threshold) {
    entry.state = "open";
    entry.openedAt = Date.now();
  }
}

export function resolveRequestOrigin(
  request: FetchRequest
): string | undefined {
  try {
    if (typeof request === "string") {
      return new URL(request).origin;
    }
    if (request instanceof URL) {
      return request.origin;
    }
    if (request instanceof Request) {
      return new URL(request.url).origin;
    }
  } catch {
    return undefined;
  }
  return undefined;
}

