// that happens across internal retry recursion, keeping circuit admission
// and slot-holding scoped to a single logical request.
export const CIRCUIT_BREAKER_CONTEXT = Symbol("ofetch.circuitBreakerContext");

export interface CircuitRequestContext {
  tracked: boolean;
  origin?: string;
  config?: ResolvedCircuitBreakerOptions;
  isProbe?: boolean;
}
